from langchain.agents import AgentExecutor
from langchain_core.messages import HumanMessage

import re

def sanitize_tool_input(message: str) -> str:
    # Replace common PII patterns
    replacements = {
        r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b': '[EMAIL]',
        r'\b\d{3}-\d{2}-\d{4}\b': '[SSN]',
        r'\b\d{10}\b': '[PHONE]'
    }
    for pattern, replacement in replacements.items():
        message = re.sub(pattern, replacement, message)
    return message

class SanitizedAgentExecutor(AgentExecutor):
    def _call(self, *args, **kwargs):
        if 'input' in kwargs:
            kwargs['input'] = sanitize_tool_input(kwargs['input'])
        return super()._call(*args, **kwargs)

# Usage
safe_agent = SanitizedAgentExecutor(agent=agent, tools=tools)

from langchain.output_parsers import PydanticOutputParser
from pydantic import BaseModel, Field
import re

class SafeOutputParser(PydanticOutputParser):
    def parse(self, text: str):
        if self._detect_pii(text):
            raise ValueError("PII detected in parsed output")
        return super().parse(text)

    def _detect_pii(self, text: str) -> bool:
        patterns = [r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b']
        return any(re.search(p, text) for p in patterns)

class CustomerResponse(BaseModel):
    name: str = Field(description="Customer name")
    action: str = Field(description="Recommended action")

parser = SafeOutputParser(pydantic_object=CustomerResponse)

prompt = ChatPromptTemplate.from_template(
    "Answer about customer {input}. {format_instructions}",
    partial_variables={"format_instructions": parser.get_format_instructions()}
)
